    tpl,
    studentName,
    uid,
    section,
    worksheetNo,
    datePerf,
    sectionContent
  } = docData;
  const pdf = new jsPDF({
    orientation: 'portrait',
    unit: 'mm',
    format: 'a4'
  });

  // ── font size helpers ──────────────────────────────────────────────────────
  const BASE = tpl.fontSize || 12; // pt → treated as mm-scaled below
  const H1 = BASE + 4;
  const H2 = BASE + 1;
  const SMALL = BASE - 1;
  const LINE_H = BASE * 0.45 * (tpl.spacing || 1.6); // mm per line

  let y = MARGIN_TOP; // current Y cursor in mm

  // ── helper: check page overflow and add new page ───────────────────────────
  const checkPage = (needed = LINE_H) => {
    if (y + needed > PAGE_H - MARGIN_BOT) {
      pdf.addPage();
      y = MARGIN_TOP;
    }
  };

  // ── helper: wrapped text block, returns new Y ──────────────────────────────
  const writeText = (text, x, maxW, lineH, align = 'left') => {
    if (!text) return;
    const lines = pdf.splitTextToSize(String(text), maxW);
    lines.forEach(line => {
      checkPage(lineH);
      pdf.text(line, align === 'center' ? PAGE_W / 2 : x, y, {
        align
      });
      y += lineH;
    });
  };

