  const hRule = (thickness = 0.4) => {
    checkPage(3);
    pdf.setDrawColor(40, 40, 40);
    pdf.setLineWidth(thickness);
    pdf.line(MARGIN_X, y, PAGE_W - MARGIN_X, y);
    y += 3;
  };

  // ══════════════════════════════════════════════════════════════════════════
  // 1. HEADER
  // ══════════════════════════════════════════════════════════════════════════
  pdf.setFont('times', 'bold');
  pdf.setFontSize(H1 + 4);
  pdf.setTextColor(10, 10, 10);
  writeText(tpl.university || 'University Name', MARGIN_X, CONTENT_W, LINE_H * 1.3, 'center');
  pdf.setFont('times', 'italic');
  pdf.setFontSize(SMALL);
  pdf.setTextColor(80, 80, 80);
  writeText('Discover. Learn. Empower.', MARGIN_X, CONTENT_W, LINE_H, 'center');
